function doCollisions(scene) {
  return __async(this, null, function* () {
    console.log("Starting Collisioning");
    const sourceBoxes = scene.filter((d) => !d.scenegraph && d.geometry !== "wireframe").map((model2) => {
      const mat = new Matrix4(model2.transformMatrix);
      const lowerBound = mat.transformAsPoint([-1, -1, -1], []);
      const upperBound = mat.transformAsPoint([1, 1, 1], []);
      return {
        "@id": model2["@id"],
        name: model2.tooltip,
        entityId: model2.entityId,
        bbox: new AABB({
          lowerBound: new Vec3(...lowerBound.map((n2, i2) => Math.min(n2, upperBound[i2]))),
          upperBound: new Vec3(...upperBound.map((n2, i2) => Math.max(n2, lowerBound[i2])))
        })
      };
    });
    const targetBoxes = [];
    for (const model2 of scene.filter((d) => !!d.scenegraph)) {
      const gltf = yield load2(model2.scenegraph, GLTFLoader, {
        DracoLoader: DracoLoader2,
        decompress: true,
        postProcess: true
      });
      for (const gltfScene of gltf.scenes ?? []) {
        traverseScene(gltfScene, new Matrix4(model2.transformMatrix), (node, modelMatrix2) => {
          if (node.mesh && node.mesh.primitives && node.mesh.primitives.length > 0) {
            for (const primitive of node.mesh.primitives) {
              if (primitive.attributes.POSITION && primitive.attributes.POSITION.min) {
                const lowerBound = modelMatrix2.transformAsPoint(primitive.attributes.POSITION.min, []);
                const upperBound = modelMatrix2.transformAsPoint(primitive.attributes.POSITION.max, []);
                targetBoxes.push({
                  "@id": model2["@id"],
                  name: node.name,
                  entityId: model2.entityId,
                  bbox: new AABB({
                    lowerBound: new Vec3(...lowerBound.map((n2, i2) => Math.min(n2, upperBound[i2]))),
                    upperBound: new Vec3(...upperBound.map((n2, i2) => Math.max(n2, lowerBound[i2])))
                  }),
                  gltf
                });
              }
            }
          }
          return true;
        });
      }
    }
    const report = [];
    const sad = [];
    for (const src of sourceBoxes) {
      const hits = [];
      for (const target of targetBoxes) {
        if (src.bbox.overlaps(target.bbox)) {
          hits.push({ "@id": target["@id"], name: target.name });
        }
      }
      if (hits.length > 0) {
        report.push({
          "@id": src.entityId,
          name: src.name,
          hits
        });
      } else {
        sad.push(src);
      }
    }
    console.log({
      sourceBoxes,
      targetBoxes,
      report,
      sad,
      maxHits: Math.max(...report.map((r2) => r2.hits.length))
    });
    const csvReport = [];
    for (const hit of report) {
      csvReport.push({
        "Tissue ID": hit["@id"],
        "Tissue Name": hit.name,
        "Hit ID": "",
        "Hit Name": ""
      });
      for (const h of hit.hits) {
        csvReport.push({
          "Tissue ID": hit["@id"],
          "Tissue Name": hit.name,
          "Hit ID": h["@id"],
          "Hit Name": h.name
        });
      }
    }
    console.log(csvReport);
    return report;
  });
}

